('signature_id', 0), ('audit_event_id', 0), ('file_ref', 0),
('change_task_ref', 0), ('calibration_ref', 0), ('maintenance_ref', 0),
('oos_ref', 0), ('complaint_ref', 0), ('em_session_ref', 0),
('em_excursion_ref', 0), ('stability_ref', 0), ('batch_ref', 0),
