('val_plan_ref', 0), ('val_report_ref', 0), ('protocol_amendment_ref', 0),
('open_item_ref', 0), ('config_baseline_ref', 0), ('access_review_ref', 0),
('revalidation_ref', 0), ('dr_test_ref', 0), ('method_val_ref', 0),
('migration_ref', 0)
ON CONFLICT (seq_name) DO NOTHING;

-- ============================================================
-- SECTION 11: DATABASE COMPATIBILITY NOTES TABLE
-- Documents which GxP controls are active for the current
-- database deployment. Inspectors may ask what controls are
-- in place. This table provides the answer at runtime.
-- ============================================================

CREATE TABLE database_compliance_controls (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    db_dialect VARCHAR(50) NOT NULL,
    -- postgresql | oracle | mysql | mariadb
    control_name VARCHAR(255) NOT NULL,
    control_type VARCHAR(100) NOT NULL,
    -- database_layer | application_layer | hybrid
    description TEXT NOT NULL,
    regulatory_citation VARCHAR(512),
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    implementation_notes TEXT,
    UNIQUE (db_dialect, control_name)
);

INSERT INTO database_compliance_controls
    (db_dialect, control_name, control_type, description, regulatory_citation, is_active) VALUES
('postgresql', 'Audit Log Append-Only (RLS)',    'database_layer',
 'PostgreSQL Row Level Security prevents UPDATE/DELETE on audit_log table at database layer. No application code can bypass this.',
 '21 CFR 11.10(e)', true),
('postgresql', 'Signature Append-Only (RLS)',    'database_layer',
 'PostgreSQL Row Level Security prevents UPDATE/DELETE on electronic_signatures table.',
